MAP
  NAME                      "Ontplofbare Oorlogsresten"
  INCLUDE                   "header.inc"
  
  WEB
    METADATA
      "team"                "SOEB"
      "ows_title"           "Ontplofbare Oorlogsresten"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "auth"                "OPENBAAR"
    END
  END


  LAYER
    NAME                    "Blindganger"
    GROUP                   "inslagen"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "geometrie FROM public.ontplofbare_oorlogsresten_inslagen_v1 WHERE detail_type = 'Blindganger' USING UNIQUE id USING SRID=28992"
    TYPE                    POLYGON
    TEMPLATE                "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
      "init=epsg:28992"
    END
    METADATA
      "ows_title"           "Blindganger"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "wms_group_title"     "Inslagen"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "multipolygon"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END
    CLASS
      NAME                  "blindganger"
      TITLE                 "Blindganer"
      STYLE
        ANTIALIAS           true
        COLOR               "#1F4892"
        OPACITY             20
      END
      STYLE
        OUTLINECOLOR        "#1F4892"
        WIDTH               2
      END
    END
  END

