  LAYER
    NAME                    "vermoedelijke_bominslagen"
    GROUP                   "inslagen"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "SELECT geometrie
                              FROM public.ontplofbare_oorlogsresten_inslagen_v1
                              WHERE detail_type IN (
                                  'Vermoedelijke bominslag(en)',
                                  'Vermoedelijke inslag',
                                  'Beschadiging door inslag',
                                  'Duidelijke inslag',
                                  'Mogelijke inslag',
                                  'Krater',
                                  'Bominslag'
                              ) USING UNIQUE id USING SRID=28992"
    TYPE                    POLYGON
    TEMPLATE                "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
      "init=epsg:28992"
    END
    METADATA
      "ows_title"           "Vermoedelijke bominslagen"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "wms_group_title"     "Inslagen"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "multipolygon"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END
    CLASS
      NAME                  "vermoedelijke_bominslagen"
      TITLE                 "Vermoedelijke bominslagen"
      STYLE
        ANTIALIAS           true
        COLOR               "#41B6E6"
        OPACITY             20
      END
      STYLE
        OUTLINECOLOR        "#41B6E6"
        WIDTH               2
      END
    END
  END

  ##### Verdachte gebieden group

  LAYER
    NAME                    "munities_en_granaten"
    GROUP                   "verdachte_gebieden"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "geometrie
                            FROM public.ontplofbare_oorlogsresten_verdachte_gebieden_v1
                            WHERE hoofdgroep IN (
                                'Geschutmunitie',
                                'Kleinkalibermunitie',
                                'Munitietoebehoren',
                                'Handgranaten',
                                'Geweergranaten',
                                'Ontstekingsinrichtingen',
                                'Munitie voor granaatwerpers'
                            )
                            USING UNIQUE id
                            USING SRID=28992"
    TYPE                    POLYGON
    TEMPLATE                "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
      "init=epsg:28992"
    END
